<?php namespace App\Http\Controllers\KuBo; use App\Http\Controllers\Controller; use App\Models\CommunityHashtag; use App\Models\CommunityPost; use App\Models\CommunityPostImage; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Facades\DB;

class PostController extends Controller {
    public function store(Request $request): JsonResponse { $request->validate(['content' => 'required_without:images|string|max:5000|nullable', 'images' => 'required_without:content|array|nullable', 'images.*' => 'string', 'visibility' => 'in:public,connections_only']); $user = Auth::user(); DB::beginTransaction(); try { $post = CommunityPost::create(['user_id' => $user->empID, 'content' => $request->content, 'visibility' => $request->visibility ?? 'public']); if ($request->images) foreach ($request->images as $i => $p) CommunityPostImage::create(['post_id' => $post->id, 'image_path' => $p, 'sort_order' => $i]); if ($request->content) { preg_match_all('/#(\w+)/', $request->content, $m); if (!empty($m[1])) foreach ($m[1] as $t) CommunityHashtag::create(['post_id' => $post->id, 'tag' => strtolower($t)]); } DB::commit(); $post->load(['user.empDetail.department','user.empDetail.position','images','hashtags']); return response()->json(['success'=>true,'message'=>'Post created!','post'=>$this->fmt($post)]); } catch(\Exception $e) { DB::rollBack(); return response()->json(['success'=>false,'message'=>'Failed'],500); } }
    public function update(Request $r, CommunityPost $post): JsonResponse { if($post->user_id !== Auth::user()->empID) return response()->json(['success'=>false,'message'=>'Unauthorized'],403); $r->validate(['content'=>'required|string|max:5000']); $post->update(['content'=>$r->content]); CommunityHashtag::where('post_id',$post->id)->delete(); preg_match_all('/#(\w+)/',$r->content,$m); if(!empty($m[1])) foreach($m[1] as $t) CommunityHashtag::create(['post_id'=>$post->id,'tag'=>strtolower($t)]); return response()->json(['success'=>true,'message'=>'Post updated!']); }
    public function destroy(CommunityPost $post): JsonResponse { $u = Auth::user(); if($post->user_id !== $u->empID && !$u->can('kuboadmin')) return response()->json(['success'=>false,'message'=>'Unauthorized'],403); $post->delete(); return response()->json(['success'=>true,'message'=>'Post deleted.']); }
    public function pin(CommunityPost $post): JsonResponse { if(!Auth::user()->can('kuboadmin')) return response()->json(['success'=>false,'message'=>'Unauthorized'],403); $post->update(['is_pinned'=>!$post->is_pinned,'pinned_by'=>Auth::user()->empID,'pinned_at'=>now()]); return response()->json(['success'=>true,'message'=>$post->is_pinned?'Pinned!':'Unpinned.','is_pinned'=>$post->is_pinned]); }
    private function fmt($p): array { return ['id'=>$p->id,'content'=>$p->content,'is_pinned'=>$p->is_pinned,'is_announcement'=>$p->is_announcement,'created_at'=>$p->created_at->diffForHumans(),'user'=>['empID'=>$p->user->empID??'','name'=>$p->user->community_full_name,'avatar'=>$p->user->community_avatar,'department'=>$p->user->empDetail?->department?->depName??'','position'=>$p->user->empDetail?->position?->posDesc??''],'images'=>$p->images->map(fn($i)=>['id'=>$i->id,'url'=>asset($i->image_path)]),'hashtags'=>$p->hashtags->pluck('tag'),'reactions'=>['total'=>0,'summary'=>[]],'current_reaction'=>null,'comments_count'=>0,'reposts_count'=>0,'is_reposted_by_me'=>false,'can_delete'=>true]; }
}